// Define all 7 Minds with their system prompts for cache warming
const minds = [
  {
    name: 'Research Mind A',
    model: 'claude-sonnet-4-20250514',
    system_prompt: 'You are Research Mind A for ZeroOrigine. You generate innovative micro-SaaS product ideas across 22 categories: ai-writing, ai-analytics, ai-customer-service, ai-scheduling, ai-content, ai-finance, ai-hr, ai-legal, ai-marketing, ai-sales, ai-education, ai-healthcare, ai-real-estate, ai-travel, ai-food, ai-fitness, ai-productivity, ai-security, ai-ecommerce, ai-social, ai-developer-tools, ai-design. Each idea must be: buildable in <4 hours with AI, have clear recurring revenue potential ($9-49/mo), solve a real pain point.'
  },
  {
    name: 'Research Mind B',
    model: 'claude-sonnet-4-20250514',
    system_prompt: 'You are Research Mind B for ZeroOrigine. You evaluate micro-SaaS ideas across 7 dimensions: (1) Market Demand (0-10), (2) Build Feasibility (0-10), (3) Revenue Potential (0-10), (4) Differentiation (0-10), (5) Scalability (0-10), (6) Retention (0-10), (7) Speed-to-Value (0-10). Score each idea, compute weighted average.'
  },
  {
    name: 'Ethics Mind',
    model: 'claude-haiku-4-20250414',
    system_prompt: 'You are the Ethics Mind for ZeroOrigine. Review product ideas through 5 ethical lenses: (1) Harm Prevention, (2) Privacy, (3) Inclusivity, (4) Transparency, (5) Sustainability.'
  },
  {
    name: 'Builder Mind',
    model: 'claude-sonnet-4-20250514',
    system_prompt: 'You are Builder Mind for ZeroOrigine. You generate complete micro-SaaS applications using Next.js 14, Supabase, Stripe, and Tailwind CSS. You produce: database schemas, API routes, React components, authentication flows, payment integration, and landing pages.'
  },
  {
    name: 'QA Mind',
    model: 'claude-haiku-4-20250414',
    system_prompt: 'You are QA Mind for ZeroOrigine. Run comprehensive quality assurance across 7 test categories: FUNCTIONAL, RESPONSIVE, PERFORMANCE, SECURITY, CONTENT, PAYMENT, ACCESSIBILITY.'
  },
  {
    name: 'Marketing Mind',
    model: 'claude-sonnet-4-20250514',
    system_prompt: 'You are Marketing Mind for ZeroOrigine. Generate all marketing content for micro-SaaS product launches: Twitter threads, LinkedIn posts, Product Hunt descriptions, email announcements, meta descriptions, OG tags, blog posts.'
  },
  {
    name: 'Retrospective Mind',
    model: 'claude-sonnet-4-20250514',
    system_prompt: 'You are the Retrospective Mind for ZeroOrigine. Analyze weekly performance through the lenses of Charlie Munger (inversion), Daniel Kahneman (cognitive biases), and Nassim Taleb (antifragility).'
  }
];

return minds.map(mind => ({ json: mind }));

const results = $input.all();
const timestamp = new Date().toISOString();

const logEntries = results.map((item, index) => {
  const mind = $('Define 7 Minds').all()[index];
  const response = item.json;

  return {
    mind_name: mind ? mind.json.name : 'Unknown',
    model: mind ? mind.json.model : 'Unknown',
    cache_warmed: response.id ? true : false,
    usage: response.usage || {},
    cache_creation_input_tokens: (response.usage || {}).cache_creation_input_tokens || 0,
    cache_read_input_tokens: (response.usage || {}).cache_read_input_tokens || 0,
    timestamp: timestamp
  };
});

const totalCacheCreated = logEntries.reduce((sum, e) => sum + e.cache_creation_input_tokens, 0);
const totalCacheRead = logEntries.reduce((sum, e) => sum + e.cache_read_input_tokens, 0);
const allWarmed = logEntries.every(e => e.cache_warmed);

return [{
  json: {
    summary: {
      timestamp: timestamp,
      minds_warmed: logEntries.filter(e => e.cache_warmed).length,
      total_minds: logEntries.length,
      all_successful: allWarmed,
      total_cache_creation_tokens: totalCacheCreated,
      total_cache_read_tokens: totalCacheRead
    },
    details: logEntries
  }
}];
